1	const PROCESSING_FEE_G = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE_G = 60;
4	const COMPONENT_UNIT_PRICE_G = 25;
5	
6	const MAIN_ITEM_BASE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	const ITEM_INSURANCE_VALUE: Record<string, number> = {
13	  sword: 1000,
14	  amulet: 600,
15	  staff: 800,
16	  potion: 400,
17	  rune: 250,
18	  moonstone: 250,
19	};
20	const DEDUCTIBLE_G = 100;
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	type Item = { type: string; cursed?: boolean; enchantment?: number };
24	type Damage = { itemType: string; amount: number };
25	type QuoteStep = { op: "quote"; items: Item[] };
26	type ClaimStep = { op: "claim"; policy: number; incident: { cause?: string; damages: Damage[] } };
27	type Step = QuoteStep | ClaimStep;
28	type Scenario = {
29	  customer: { yearsWithMHPCO: number };
30	  steps: Step[];
31	};
32	
33	const sum = (numbers: number[]): number =>
34	  numbers.reduce((acc, n) => acc + n, 0);
35	
36	const componentBaseForGroup = (count: number): number =>
37	  count === BLOCK_SIZE ? BLOCK_PRICE_G : count * COMPONENT_UNIT_PRICE_G;
38	
39	const componentBaseTotal = (componentItems: Item[]): number => {
40	  const counts = new Map<string, number>();
41	  for (const item of componentItems) {
42	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
43	  }
44	  return sum([...counts.values()].map(componentBaseForGroup));
45	};
46	
47	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE[item.type] ?? 0;
48	
49	const CURSE_RATE = 0.5;
50	const HIGH_ENCHANTMENT_RATE = 0.3;
51	const HIGH_ENCHANTMENT_THRESHOLD = 5;
52	
53	const isCursed = (item: Item): boolean => item.cursed === true;
54	const isHighlyEnchanted = (item: Item): boolean =>
55	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
56	
57	const mainItemModifiers = (item: Item): number => {
58	  const base = mainItemBase(item);
59	  const rate =
60	    (isCursed(item) ? CURSE_RATE : 0) +
61	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
62	  return base * rate;
63	};
64	
65	const firstInsuranceSurcharge = (policyBase: number): number => policyBase / 10;
66	
67	const loyaltyDiscount = (policyBase: number, yearsWithMHPCO: number): number =>
68	  yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
69	
70	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
71	
72	const followUpDiscount = (policyBase: number, isFollowUp: boolean): number =>
73	  isFollowUp ? policyBase * 0.15 : 0;
74	
75	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
76	  const mainItems = items.filter((i) => !isComponent(i));
77	  const componentItems = items.filter(isComponent);
78	  const policyBase = sum(mainItems.map(mainItemBase)) + componentBaseTotal(componentItems);
79	  const itemModifiersTotal = sum(mainItems.map(mainItemModifiers));
80	  const surcharges = firstInsuranceSurcharge(policyBase);
81	  const discounts = loyaltyDiscount(policyBase, yearsWithMHPCO) + followUpDiscount(policyBase, isFollowUp);
82	  return Math.ceil(policyBase + itemModifiersTotal + surcharges - discounts + PROCESSING_FEE_G);
83	};
84	
85	const insuranceSum = (items: Item[]): number =>
86	  sum(items.map((i) => ITEM_INSURANCE_VALUE[i.type] ?? 0));
87	
88	type Policy = { items: Item[]; remainingCap: number };
89	
90	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
91	
92	const effectiveDamageAmount = (damage: Damage, items: Item[]): number => {
93	  const item = items.find((i) => i.type === damage.itemType);
94	  if (item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
95	    return Math.floor(damage.amount * 0.5);
96	  }
97	  return damage.amount;
98	};
99	
100	const damagePayout = (damage: Damage, remainingCap: number, items: Item[]): number =>
101	  Math.min(effectiveDamageAmount(damage, items) - DEDUCTIBLE_G, remainingCap);
102	
103	const applyDamages = (
104	  damages: Damage[],
105	  startingCap: number,
106	  items: Item[],
107	): { payout: number; remainingCap: number } =>
108	  damages.reduce(
109	    ({ payout, remainingCap }, damage) => {
110	      const next = damagePayout(damage, remainingCap, items);
111	      return { payout: payout + next, remainingCap: remainingCap - next };
112	    },
113	    { payout: 0, remainingCap: startingCap },
114	  );
115	
116	const initialCap = (items: Item[]): number => 2 * insuranceSum(items);
117	
118	export const runScenario = (scenario: unknown): unknown => {
119	  const { customer, steps } = scenario as Scenario;
120	  const policies: Record<number, Policy> = {};
121	  let priorQuoteCount = 0;
122	  const results = steps.map((step, index) => {
123	    if (step.op === "quote") {
124	      const isFollowUp = priorQuoteCount > 0;
125	      priorQuoteCount += 1;
126	      policies[index] = { items: step.items, remainingCap: initialCap(step.items) };
127	      return { premium: quotePremium(step.items, customer.yearsWithMHPCO, isFollowUp) };
128	    }
129	    const policy = policies[step.policy];
130	    const result = applyDamages(step.incident.damages, policy.remainingCap, policy.items);
131	    policy.remainingCap = result.remainingCap;
132	    return result;
133	  });
134	  return { results };
135	};
